function Quiz(i){var t=this,n=$("#"+i);this.tabID=i;n.find("[name=hidId]").val();this.rebindEl=function(){},this.loadOnReady=function(){questionRows=n.find(".question-row"),questionRows.each(function(){0==$(this).find(".detail-item .transaction-detail-row").length&&addNewTemplateRow("item-row-template",null,$(this),t.rebindEl)}),t.rebindEl()}}